      flake-parts,
      treefmt-nix,
      nixpkgs,
      nixpkgs-stable,
      llm-agents,
      nix-steipete-tools,
      ghostty,
      gh-nippou,
      gh-graph,
      brew-nix,
      ...
    }:
    let
      mkPkgs =
        system:
        let
          isDarwin = builtins.match ".*-darwin" system != null;
        in
        import nixpkgs {
          inherit system;
          config = {
            allowUnfree = true;
            android_sdk.accept_license = true;
          };
          overlays = [
            (_final: _prev: {
              stable = import nixpkgs-stable {
                inherit system;
                config = {
                  allowUnfree = true;
                };
              };
            })
            llm-agents.overlays.default
            (_final: _prev: {
              _nix-steipete-tools = nix-steipete-tools;
              _ghostty = ghostty;
              _repiq = inputs.repiq;
              _cage = inputs.cage;
              _moonbit-overlay = inputs.moonbit-overlay;
